import{_ as a,o as e,c as t,ae as i}from"./chunks/framework.5iO6U-54.js";const u=JSON.parse('{"title":"SQL 拼接设计","description":"","frontmatter":{},"headers":[],"relativePath":"design/sql-builder.md","filePath":"design/sql-builder.md"}'),n={name:"design/sql-builder.md"};function l(d,s,o,r,p,h){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="sql-拼接设计" tabindex="-1">SQL 拼接设计 <a class="header-anchor" href="#sql-拼接设计" aria-label="Permalink to &quot;SQL 拼接设计&quot;">​</a></h1><p>go-cube 将 CubeJS 兼容的 JSON 查询请求翻译为 ClickHouse SQL，入口为 <code>api/query.go</code> 的 <code>BuildQuery(req, cube) → (sql, params, error)</code>。</p><h2 id="整体数据流" tabindex="-1">整体数据流 <a class="header-anchor" href="#整体数据流" aria-label="Permalink to &quot;整体数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QueryRequest (CubeJS JSON)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>BuildQuery</span></span>
<span class="line"><span>    ├── SELECT   dimensions + measures + granularity 截断列</span></span>
<span class="line"><span>    ├── FROM     cube.GetSQLTable()，支持 {filter.&lt;field&gt;} 占位符替换</span></span>
<span class="line"><span>    ├── WHERE    segments + filters(dimension 字段) + timeDimensions</span></span>
<span class="line"><span>    ├── GROUP BY 仅当 measures 存在时，使用 field.SQL（非别名）</span></span>
<span class="line"><span>    ├── HAVING   filters(measure 字段)</span></span>
<span class="line"><span>    ├── ORDER BY 支持 granularity 表达式，查 granByDim map</span></span>
<span class="line"><span>    └── LIMIT / OFFSET</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>(sqlString, []interface{} params)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>ClickHouse HTTP client（手动 ? 占位符替换）</span></span></code></pre></div><h2 id="各子句生成规则" tabindex="-1">各子句生成规则 <a class="header-anchor" href="#各子句生成规则" aria-label="Permalink to &quot;各子句生成规则&quot;">​</a></h2><h3 id="select" tabindex="-1">SELECT <a class="header-anchor" href="#select" aria-label="Permalink to &quot;SELECT&quot;">​</a></h3><p>每个 dimension / measure 解析为 <code>field.SQL AS &quot;CubeName.fieldName&quot;</code>。</p><p>有 granularity 的时间维度额外追加截断列，例如：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">toStartOfMinute(ts) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;AccessView.ts.minute&quot;</span></span></code></pre></div><h3 id="from" tabindex="-1">FROM <a class="header-anchor" href="#from" aria-label="Permalink to &quot;FROM&quot;">​</a></h3><p><code>cube.GetSQLTable()</code> 返回：</p><ul><li>若 cube 定义了 <code>sql_table</code>：直接返回表名</li><li>若定义了 <code>sql</code>（子查询）：返回 <code>(SELECT ...) AS CubeName</code></li></ul><p>子查询内可含 <code>{filter.&lt;field&gt;}</code> 占位符，在 timeDimensions 循环内同步替换（见下文）。</p><h3 id="where-having-路由" tabindex="-1">WHERE / HAVING 路由 <a class="header-anchor" href="#where-having-路由" aria-label="Permalink to &quot;WHERE / HAVING 路由&quot;">​</a></h3><p><code>isMeasure(member)</code> 检查字段是否在 <code>cube.Measures</code> 中：</p><ul><li>dimension 字段 → WHERE</li><li>measure 字段 → HAVING</li></ul><p>OR 复合条件：任一子条件是 measure 则整体走 HAVING。</p><p>segments 直接将 <code>segment.SQL</code> 追加到 WHERE，无参数绑定。</p><h3 id="group-by" tabindex="-1">GROUP BY <a class="header-anchor" href="#group-by" aria-label="Permalink to &quot;GROUP BY&quot;">​</a></h3><p>请求包含 measures 且同时有 dimensions 或带 granularity 的时间维度时生成。使用 <code>field.SQL</code>（原始表达式），不使用 SELECT 别名，兼容 ClickHouse 语义。</p><p>仅有 measures、无任何 dimensions / granularity 时，不生成 GROUP BY——ClickHouse 对聚合函数做全表聚合，无需显式 GROUP BY。</p><h3 id="order-by" tabindex="-1">ORDER BY <a class="header-anchor" href="#order-by" aria-label="Permalink to &quot;ORDER BY&quot;">​</a></h3><p><strong>显式排序</strong>：请求携带 <code>order</code> 字段时，按其指定的成员和方向生成 ORDER BY。 granularity 时间维度的排序使用截断表达式（如 <code>toStartOfMinute(ts)</code>）而非原始列名。 实现上通过 <code>granByDim map[string]granularityCol</code>（key = <code>td.Dimension</code>）在函数入口一次性计算，SELECT / GROUP BY / ORDER BY 三处共用，避免重复解析。</p><p><strong>隐式排序</strong>（兼容 CubeJS 默认行为）：<code>order</code> 为空且请求包含带 granularity 的时间维度时，自动按 <code>timeDimensions</code> 中第一个有粒度的维度 <strong>ASC</strong> 排序：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 示例：granularity = &quot;minute&quot;，无 order 字段</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> toStartOfMinute(ts) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ASC</span></span></code></pre></div><p>这与 CubeJS 的隐式排序规则一致（第一个带粒度的时间维度升序），解决前端图表 x 轴时间乱序问题。若不希望隐式排序，需显式传入 <code>order: []</code>（空数组）—— 但当前实现会将空数组解析为 0 个 OrderItem，与未传 order 等价，即无法通过空数组关闭隐式排序（CubeJS 完整语义，此处简化处理）。</p><h2 id="参数绑定与顺序保证" tabindex="-1">参数绑定与顺序保证 <a class="header-anchor" href="#参数绑定与顺序保证" aria-label="Permalink to &quot;参数绑定与顺序保证&quot;">​</a></h2><p>ClickHouse HTTP 接口不支持 prepared statement，参数以 <code>?</code> 占位符按出现顺序做字符串替换。</p><p>WHERE 参数（<code>whereParams</code>）和 HAVING 参数（<code>havingParams</code>）<strong>必须分两组收集</strong>，最后 <code>append(whereParams, havingParams...)</code> 合并。</p><p>原因：filter 循环里 WHERE/HAVING 条件的 append 顺序取决于请求中 filter 的排列，但 SQL 字符串里 WHERE 的 <code>?</code> 永远在 HAVING 的 <code>?</code> 之前，两组分离才能保证顺序正确。</p><h2 id="子查询占位符替换-filter-field" tabindex="-1">子查询占位符替换（{filter.&lt;field&gt;}） <a class="header-anchor" href="#子查询占位符替换-filter-field" aria-label="Permalink to &quot;子查询占位符替换（{filter.\\&lt;field\\&gt;}）&quot;">​</a></h2><p>部分 cube 的 <code>sql</code> 是多层子查询（如 <code>ApiView</code>），时间过滤需下推到最内层原始表，否则会全表扫描后再过滤。</p><p><strong>机制</strong>：子查询 SQL 中用 <code>{filter.ts}</code> 作占位符，<code>BuildQuery</code> 在 timeDimensions 循环内，生成外层 WHERE 条件的同时，用相同的 dateRange 生成针对原始列名的条件，替换占位符：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- ApiView.yaml 中的子查询片段</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.access_sample_raw</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 替换后（dateRange = &quot;from 15 minutes ago to 15 minutes from now&quot;）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> INTERVAL </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> MINUTE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> INTERVAL </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> MINUTE</span></span></code></pre></div><p>FROM 写入被延迟到 timeDimensions 循环结束后，确保所有占位符已替换。若循环结束仍有未替换的 <code>{filter.</code>，返回 error。</p><h2 id="array-类型字段的过滤" tabindex="-1">array 类型字段的过滤 <a class="header-anchor" href="#array-类型字段的过滤" aria-label="Permalink to &quot;array 类型字段的过滤&quot;">​</a></h2><p><code>type: array</code> 字段不使用 <code>IN</code>，使用 ClickHouse 数组函数：</p><table tabindex="0"><thead><tr><th>场景</th><th>生成 SQL</th></tr></thead><tbody><tr><td>单值 equals</td><td><code>has(arr, ?)</code></td></tr><tr><td>多值 equals</td><td><code>hasAll(arr, [?,?,...])</code></td></tr><tr><td>多值 contains</td><td><code>hasAny(arr, [?,?,...])</code></td></tr><tr><td>notEquals / notContains</td><td>前缀 <code>NOT</code></td></tr></tbody></table><h2 id="set-notset-过滤" tabindex="-1">set / notSet 过滤 <a class="header-anchor" href="#set-notset-过滤" aria-label="Permalink to &quot;set / notSet 过滤&quot;">​</a></h2><p><code>set</code> 和 <code>notSet</code> 是两个特殊操作符，不需要 values，直接检查字段是否为空：</p><table tabindex="0"><thead><tr><th>操作符</th><th>生成 SQL</th></tr></thead><tbody><tr><td><code>set</code></td><td><code>notEmpty(field)</code></td></tr><tr><td><code>notSet</code></td><td><code>empty(field)</code></td></tr></tbody></table><h2 id="相对时间表达式" tabindex="-1">相对时间表达式 <a class="header-anchor" href="#相对时间表达式" aria-label="Permalink to &quot;相对时间表达式&quot;">​</a></h2><p>相对时间直接翻译为 ClickHouse 函数表达式，内联进 SQL，不产生参数绑定：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;from 15 minutes ago to 15 minutes from now&quot;</span></span>
<span class="line"><span>→ ts &gt;= now() - INTERVAL 15 MINUTE AND ts &lt;= now() + INTERVAL 15 MINUTE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;last month&quot;</span></span>
<span class="line"><span>→ ts &gt;= toStartOfMonth(addMonths(now(), -1)) AND ts &lt;= toStartOfMonth(now())</span></span></code></pre></div><p>绝对时间范围（数组格式 <code>[&quot;2026-01-01&quot;, &quot;2026-01-31&quot;]</code>）使用 <code>?</code> 绑定。</p><h2 id="有意省略的功能" tabindex="-1">有意省略的功能 <a class="header-anchor" href="#有意省略的功能" aria-label="Permalink to &quot;有意省略的功能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><code>timezone</code> 时区转换</td><td>字段保留兼容性，ClickHouse 服务端已配置时区，Go 层不处理</td></tr><tr><td>response 元数据字段</td><td><code>transformedQuery</code>、<code>annotation</code> 等前端不读取，省略</td></tr><tr><td>SQL 预编译</td><td>ClickHouse HTTP 接口不支持，用字符串替换代替</td></tr><tr><td>缓存 / 预聚合</td><td>CubeJS 核心复杂度来源，完全省略</td></tr></tbody></table>`,47)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
